     1→---
     2→name: database-skill
     3→description: Comprehensive MySQL database management with Knex.js including schema design, migrations, models, DTOs, validation, query optimization, and read/write replica management. Use when working with database schemas, creating tables, writing migrations, building models, optimizing queries, or any database-related work. CRITICAL SAFETY RULE - NEVER execute DROP, DELETE, or TRUNCATE operations directly via database connection - only create migrations that contain these operations.
     4→---
     5→
     6→# Database Skill
     7→
     8→Complete MySQL database management with Knex.js for NestJS applications following project patterns.
     9→
    10→## When to Use
    11→
    12→Trigger for ALL database-related work:
    13→- Creating/modifying tables
    14→- Writing migrations
    15→- Building models with CRUD operations
    16→- Creating DTOs with validation
    17→- Optimizing queries
    18→- Database schema design
    19→- Connection management
    20→- Read/write replica pattern
    21→
    22→## Critical Safety Rules
    23→
    24→**NEVER execute these directly via connection:**
    25→- ❌ DROP TABLE
    26→- ❌ DELETE FROM
    27→- ❌ TRUNCATE
    28→- ❌ DROP DATABASE
    29→- ❌ Any destructive operation
    30→
    31→**ONLY via migrations:**
    32→- ✅ Create migrations containing DROP/DELETE/TRUNCATE
    33→- ✅ Execute migrations with `npm run migrate`
    34→
    35→**Always allowed:**
    36→- ✅ SELECT queries (read data)
    37→- ✅ Read schemas and structures
    38→- ✅ INSERT/UPDATE via models in transactions
    39→
    40→## Database Structure
    41→
    42→### Table Naming Convention
    43→
    44→Table names stored in constants:
    45→
    46→```typescript
    47→// src/constants/db.constant.ts
    48→export const TABLE_NAME_STYLES = 'styles';
    49→export const TABLE_NAME_STYLES_HASH = 'styles_hash';
    50→```
    51→
    52→### Standard Schema Pattern
    53→
    54→All tables include:
    55→- `_id` UUID primary key
    56→- `created_at` timestamp (default now)
    57→- `updated_at` timestamp (default now)
    58→- `deleted_at` timestamp nullable (soft delete)
    59→- Appropriate indexes
    60→- Unique constraints with soft delete predicate
    61→
    62→## Migration Workflow
    63→
    64→### 1. Create Migration
    65→
    66→```bash
    67→npm run migrate:make table_name_or_description
    68→```
    69→
    70→Creates file: `src/migrations/{timestamp}_{description}.ts`
    71→
    72→### 2. Migration Pattern
    73→
    74→```typescript
    75→import { randomUUID } from 'node:crypto';
    76→import { Logger } from '@nestjs/common';
    77→import { TABLE_NAME_YOUR_TABLE } from '@constants/db.constant';
    78→import type { Knex } from 'knex';
    79→
    80→const logger = new Logger('migration_file_name.ts');
    81→
    82→export async function up(knex: Knex): Promise<void> {
    83→  await knex.transaction(async (trx) => {
    84→    await trx.schema.createTable(TABLE_NAME_YOUR_TABLE, (table) => {
    85→      // Primary key
    86→      table.uuid('_id').primary();
    87→
    88→      // Business fields
    89→      table.bigint('entity_id').notNullable();
    90→      table.string('name', 255).notNullable();
    91→      table.text('description').nullable();
    92→      table.integer('count').notNullable().defaultTo(0);
    93→
    94→      // Timestamps
    95→      table.timestamp('created_at').defaultTo(trx.fn.now());
    96→      table.timestamp('updated_at').defaultTo(trx.fn.now());
    97→      table.timestamp('deleted_at').nullable();
    98→
    99→      // Indexes
   100→      table.index(['entity_id', 'deleted_at']);
   101→      table.index(['name', 'deleted_at']);
   102→
   103→      // Unique constraints with soft delete predicate
   104→      table.unique(['entity_id'], {
   105→        predicate: trx.whereNull('deleted_at')
   106→      });
   107→    });
   108→
   109→    logger.log('Table created successfully');
   110→  });
   111→}
   112→
   113→export async function down(knex: Knex): Promise<void> {
   114→  await knex.transaction(async (trx) => {
   115→    await trx.schema.dropTableIfExists(TABLE_NAME_YOUR_TABLE);
   116→  });
   117→}
   118→```
   119→
   120→### 3. Run Migrations
   121→
   122→```bash
   123→# Run all pending
   124→npm run migrate
   125→
   126→# Run one up
   127→npm run migrate:up
   128→
   129→# Run one down
   130→npm run migrate:down
   131→
   132→# Rollback last batch
   133→npm run migrate:rollback
   134→
   135→# Production
   136→npm run migrate:prod
   137→```
   138→
   139→### 4. Migration with Data Seeding
   140→
   141→```typescript
   142→export async function up(knex: Knex): Promise<void> {
   143→  await knex.transaction(async (trx) => {
   144→    // Create table
   145→    await trx.schema.createTable(TABLE_NAME, (table) => {
   146→      // schema
   147→    });
   148→
   149→    // Seed data in batches
   150→    const data = [...]; // Your data
   151→    const batchSize = 100;
   152→    const batches = [];
   153→
   154→    for (let i = 0; i < data.length; i += batchSize) {
   155→      batches.push(data.slice(i, i + batchSize));
   156→    }
   157→
   158→    for (const batch of batches) {
   159→      const insertData = batch.map((item) => ({
   160→        _id: randomUUID(),
   161→        // map fields
   162→      }));
   163→
   164→      await trx(TABLE_NAME).insert(insertData);
   165→    }
   166→
   167→    logger.log(`Inserted ${data.length} records`);
   168→  });
   169→}
   170→```
   171→
   172→## Model Pattern
   173→
   174→### File Structure
   175→
   176→```
   177→src/modules/db/{entity}/
   178→├── models/
   179→│   └── {entity}.model.ts
   180→├── dto/
   181→│   ├── {entity}.base.dto.ts
   182→│   ├── {entity}.create.dto.ts
   183→│   └── {entity}.update.dto.ts
   184→├── types/
   185→│   ├── {entity}.base.interface.ts
   186→│   ├── {entity}.create.interface.ts
   187→│   └── {entity}.update.interface.ts
   188→└── {entity}.module.ts
   189→```
   190→
   191→### Model Implementation
   192→
   193→```typescript
   194→import { randomUUID } from 'node:crypto';
   195→import { Injectable, Logger } from '@nestjs/common';
   196→import { InjectConnection } from 'nest-knexjs';
   197→import { Knex } from 'knex';
   198→import { instanceToPlain, plainToInstance } from 'class-transformer';
   199→import { validate, ValidationError } from 'class-validator';
   200→
   201→import { BaseEntityDto } from './dto/entity.base.dto';
   202→import { CreateEntityDto } from './dto/entity.create.dto';
   203→import { UpdateEntityDto } from './dto/entity.update.dto';
   204→import { IEntityBase } from './types/entity.base.interface';
   205→import { IEntityCreate } from './types/entity.create.interface';
   206→import { IEntityUpdate } from './types/entity.update.interface';
   207→
   208→import {
   209→  KNEX_READ_CONNECTION,
   210→  KNEX_WRITE_CONNECTION,
   211→  TABLE_NAME_ENTITY,
   212→} from '@constants/db.constant';
   213→
   214→@Injectable()
   215→export class EntityModel {
   216→  private readonly logger = new Logger(EntityModel.name);
   217→  private readonly tableName = TABLE_NAME_ENTITY;
   218→
   219→  constructor(
   220→    @InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
   221→    @InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
   222→  ) {}
   223→
   224→  async create({ data }: { data: IEntityCreate }): Promise<IEntityBase> {
   225→    const _id = randomUUID();
   226→
   227→    const entityData: IEntityCreate & { _id: string } = {
   228→      ...data,
   229→      _id,
   230→    };
   231→
   232→    const dto = plainToInstance(CreateEntityDto, entityData);
   233→    const errors = await validate(dto);
   234→
   235→    if (errors.length > 0) {
   236→      this.logger.error(
   237→        `Validation failed: ${this.formatValidationErrors({ errors })}`
   238→      );
   239→      throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
   240→    }
   241→
   242→    try {
   243→      const res = await this.knexWrite.transaction(async (trx) => {
   244→        await trx(this.tableName).insert(entityData);
   245→
   246→        return await trx<BaseEntityDto>(this.tableName)
   247→          .where('_id', _id)
   248→          .whereNull('deleted_at')
   249→          .first();
   250→      });
   251→
   252→      if (!res) {
   253→        throw new Error(`Failed to insert entity with ID ${_id}`);
   254→      }
   255→
   256→      this.logger.debug(`Inserted entity with ID ${_id}`);
   257→      return instanceToPlain<BaseEntityDto>(res) as IEntityBase;
   258→    } catch (error) {
   259→      this.logger.error(`Failed to create entity: ${(error as Error).message}`);
   260→      throw error;
   261→    }
   262→  }
   263→
   264→  async findById({ _id }: { _id: string }): Promise<IEntityBase | null> {
   265→    try {
   266→      const result = await this.knexRead<BaseEntityDto>(this.tableName)
   267→        .where({ _id })
   268→        .whereNull('deleted_at')
   269→        .first();
   270→
   271→      if (!result) {
   272→        this.logger.warn(`No entity found for ID ${_id}`);
   273→        return null;
   274→      }
   275→
   276→      this.logger.debug(`Found entity for ID ${_id}`);
   277→      return instanceToPlain<BaseEntityDto>(result) as IEntityBase;
   278→    } catch (error) {
   279→      this.logger.error(`Failed to find entity: ${(error as Error).message}`);
   280→      throw error;
   281→    }
   282→  }
   283→
   284→  async findMany({
   285→    limit = 10,
   286→    offset = 0,
   287→  }: {
   288→    limit?: number;
   289→    offset?: number;
   290→  }): Promise<IEntityBase[]> {
   291→    try {
   292→      const results = await this.knexRead<BaseEntityDto>(this.tableName)
   293→        .whereNull('deleted_at')
   294→        .limit(limit)
   295→        .offset(offset)
   296→        .orderBy('created_at', 'desc');
   297→
   298→      this.logger.debug(`Found ${results.length} entities`);
   299→      return results.map((r) => instanceToPlain<BaseEntityDto>(r) as IEntityBase);
   300→    } catch (error) {
   301→      this.logger.error(`Failed to find entities: ${(error as Error).message}`);
   302→      throw error;
   303→    }
   304→  }
   305→
   306→  async update({
   307→    _id,
   308→    data,
   309→  }: {
   310→    _id: string;
   311→    data: Partial<IEntityUpdate>;
   312→  }): Promise<IEntityBase | null> {
   313→    const dto = plainToInstance(UpdateEntityDto, data);
   314→    const errors = await validate(dto, { skipMissingProperties: true });
   315→
   316→    if (errors.length > 0) {
   317→      this.logger.error(
   318→        `Validation failed: ${this.formatValidationErrors({ errors })}`
   319→      );
   320→      throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
   321→    }
   322→
   323→    try {
   324→      const res = await this.knexWrite.transaction(async (trx) => {
   325→        await trx(this.tableName)
   326→          .where({ _id })
   327→          .whereNull('deleted_at')
   328→          .update({ ...data, updated_at: trx.fn.now() });
   329→
   330→        return await trx<IEntityBase>(this.tableName)
   331→          .where({ _id })
   332→          .whereNull('deleted_at')
   333→          .first();
   334→      });
   335→
   336→      if (!res) {
   337→        this.logger.warn(`No entity found for ID ${_id}`);
   338→        return null;
   339→      }
   340→
   341→      this.logger.debug(`Updated entity for ID ${_id}`);
   342→      return instanceToPlain<BaseEntityDto>(res) as IEntityBase;
   343→    } catch (error) {
   344→      this.logger.error(`Failed to update entity: ${(error as Error).message}`);
   345→      throw error;
   346→    }
   347→  }
   348→
   349→  async softDelete({ _id }: { _id: string }): Promise<void> {
   350→    try {
   351→      await this.knexWrite(this.tableName)
   352→        .where({ _id })
   353→        .whereNull('deleted_at')
   354→        .update({
   355→          deleted_at: this.knexWrite.fn.now(),
   356→          updated_at: this.knexWrite.fn.now(),
   357→        });
   358→
   359→      this.logger.debug(`Soft deleted entity for ID ${_id}`);
   360→    } catch (error) {
   361→      this.logger.error(`Failed to soft delete entity: ${(error as Error).message}`);
   362→      throw error;
   363→    }
   364→  }
   365→
   366→  private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
   367→    return errors
   368→      .map((error) =>
   369→        `${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`
   370→      )
   371→      .join('; ');
   372→  }
   373→}
   374→```
   375→
   376→## DTO Pattern
   377→
   378→### Base DTO
   379→
   380→```typescript
   381→import { Transform } from 'class-transformer';
   382→import {
   383→  IsUUID,
   384→  IsString,
   385→  IsNotEmpty,
   386→  IsOptional,
   387→  IsDateString,
   388→  IsNumber,
   389→  MaxLength,
   390→  MinLength,
   391→} from 'class-validator';
   392→
   393→import { IEntityBase } from '../types/entity.base.interface';
   394→
   395→export class BaseEntityDto {
   396→  @IsUUID(4)
   397→  _id: IEntityBase['_id'];
   398→
   399→  @IsNumber()
   400→  @IsNotEmpty()
   401→  entity_id: IEntityBase['entity_id'];
   402→
   403→  @IsString()
   404→  @IsNotEmpty()
   405→  @MaxLength(255)
   406→  name: IEntityBase['name'];
   407→
   408→  @IsString()
   409→  @IsOptional()
   410→  @MaxLength(1000)
   411→  description: IEntityBase['description'];
   412→
   413→  @IsOptional()
   414→  @Transform(({ value }: { value: string | number | null }) =>
   415→    value ? new Date(value) : null
   416→  )
   417→  @IsDateString()
   418→  created_at: IEntityBase['created_at'];
   419→
   420→  @IsOptional()
   421→  @Transform(({ value }: { value: string | number | null }) =>
   422→    value ? new Date(value) : null
   423→  )
   424→  @IsDateString()
   425→  updated_at: IEntityBase['updated_at'];
   426→
   427→  @IsOptional()
   428→  @Transform(({ value }: { value: string | number | null }) =>
   429→    value ? new Date(value) : null
   430→  )
   431→  @IsDateString()
   432→  deleted_at: IEntityBase['deleted_at'];
   433→}
   434→```
   435→
   436→### Create DTO
   437→
   438→```typescript
   439→import { OmitType } from '@nestjs/swagger';
   440→import { BaseEntityDto } from './entity.base.dto';
   441→
   442→export class CreateEntityDto extends OmitType(BaseEntityDto, [
   443→  '_id',
   444→  'created_at',
   445→  'updated_at',
   446→  'deleted_at',
   447→] as const) {}
   448→```
   449→
   450→### Update DTO
   451→
   452→```typescript
   453→import { PartialType, OmitType } from '@nestjs/swagger';
   454→import { BaseEntityDto } from './entity.base.dto';
   455→
   456→export class UpdateEntityDto extends PartialType(
   457→  OmitType(BaseEntityDto, [
   458→    '_id',
   459→    'created_at',
   460→    'updated_at',
   461→    'deleted_at',
   462→  ] as const)
   463→) {}
   464→```
