   466→## Interface Pattern
   467→
   468→### Base Interface
   469→
   470→```typescript
   471→export interface IEntityBase {
   472→  _id: string;
   473→  entity_id: number;
   474→  name: string;
   475→  description: string | null;
   476→  created_at: Date;
   477→  updated_at: Date;
   478→  deleted_at: Date | null;
   479→}
   480→```
   481→
   482→### Create Interface
   483→
   484→```typescript
   485→import { IEntityBase } from './entity.base.interface';
   486→
   487→export type IEntityCreate = Omit<
   488→  IEntityBase,
   489→  '_id' | 'created_at' | 'updated_at' | 'deleted_at'
   490→>;
   491→```
   492→
   493→### Update Interface
   494→
   495→```typescript
   496→import { IEntityBase } from './entity.base.interface';
   497→
   498→export type IEntityUpdate = Partial<
   499→  Omit<IEntityBase, '_id' | 'created_at' | 'updated_at' | 'deleted_at'>
   500→>;
   501→```
