   503→## Query Optimization
   504→
   505→### Use Indexes
   506→
   507→```typescript
   508→// In migration
   509→table.index(['field1', 'field2', 'deleted_at']);
   510→table.index(['foreign_key', 'status', 'deleted_at']);
   511→```
   512→
   513→### Select Specific Fields
   514→
   515→```typescript
   516→// ❌ Bad - selects all fields
   517→const data = await this.knexRead('table').where({ id });
   518→
   519→// ✅ Good - only needed fields
   520→const data = await this.knexRead('table')
   521→  .select('id', 'name', 'email')
   522→  .where({ id });
   523→```
   524→
   525→### Use Pagination
   526→
   527→```typescript
   528→async findPaginated({
   529→  limit = 10,
   530→  offset = 0,
   531→}: {
   532→  limit?: number;
   533→  offset?: number;
   534→}): Promise<IEntityBase[]> {
   535→  return this.knexRead<BaseEntityDto>(this.tableName)
   536→    .whereNull('deleted_at')
   537→    .limit(limit)
   538→    .offset(offset)
   539→    .orderBy('created_at', 'desc');
   540→}
   541→```
   542→
   543→### Efficient Joins
   544→
   545→```typescript
   546→const data = await this.knexRead('users as u')
   547→  .join('orders as o', 'u.id', 'o.user_id')
   548→  .select('u.id', 'u.name', 'o.total')
   549→  .where('u.deleted_at', null)
   550→  .where('o.deleted_at', null);
   551→```
   552→
   553→### Use Transactions for Multiple Writes
   554→
   555→```typescript
   556→async createWithRelations({ data }: { data: Data }): Promise<Result> {
   557→  return this.knexWrite.transaction(async (trx) => {
   558→    const entity = await trx('entities').insert(data).returning('*');
   559→
   560→    await trx('relations').insert({
   561→      entity_id: entity[0].id,
   562→      related_data: data.related,
   563→    });
   564→
   565→    return entity[0];
   566→  });
   567→}
   568→```
   569→
   570→### Batch Operations
   571→
   572→```typescript
   573→async createBatch({ items }: { items: IEntityCreate[] }): Promise<void> {
   574→  const batchSize = 100;
   575→
   576→  for (let i = 0; i < items.length; i += batchSize) {
   577→    const batch = items.slice(i, i + batchSize);
   578→
   579→    await this.knexWrite.transaction(async (trx) => {
   580→      const insertData = batch.map((item) => ({
   581→        _id: randomUUID(),
   582→        ...item,
   583→      }));
   584→
   585→      await trx(this.tableName).insert(insertData);
   586→    });
   587→  }
   588→
   589→  this.logger.log(`Inserted ${items.length} records in batches`);
   590→}
   591→```
